            memcpy(scratch_, key_ptr, key_copy_len);
            scratch_[key_copy_len] = 0;
            
            offset += key_len;
            if (offset + 4 > file_size_) goto truncate;
            
            uint32_t type = *(uint32_t*)(view_ + offset);
            offset += 4;
            
